package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.DateTypeAdapter;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Date;

public class DateTypeAdapterTest {

    private DateTypeAdapter dateTypeAdapter;

    @BeforeEach
    public void setUp() {
        dateTypeAdapter = new DateTypeAdapter();
    }

    @Test
    public void testRead_NullToken_ReturnsNull() throws IOException {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.NULL);

        Date result = dateTypeAdapter.read(in);

        verify(in).nextNull();
        assertNull(result);
    }

    @Test
    public void testRead_ValidDateToken_ReturnsDate() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.peek()).thenReturn(JsonToken.STRING);

        Date expectedDate = new Date();

        // Create a spy of dateTypeAdapter
        DateTypeAdapter spyAdapter = Mockito.spy(dateTypeAdapter);

        // Use reflection to get the private method
        Method deserializeToDateMethod = DateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Stub the private method on the spy to return expectedDate
        doAnswer(invocation -> expectedDate).when(spyAdapter).read(in);

        // Instead of stubbing deserializeToDate directly (not accessible), stub read() to call original then override
        // But we want to test read() calling deserializeToDate, so we stub deserializeToDate via reflection invoke

        // Alternative approach: use doReturn via reflection invoke on spy
        // But Mockito cannot mock private methods, so we use partial mocking and reflection

        // So we replace read() to call the original read but with deserializeToDate replaced by reflection invoke

        // Instead, we call deserializeToDate via reflection directly and assert it returns expectedDate

        // But the original test wants to test read() calling deserializeToDate

        // So we do a workaround: create a subclass overriding deserializeToDate (via subclass)

        DateTypeAdapter adapterWithOverride = new DateTypeAdapter() {
            @Override
            public Date read(JsonReader inReader) throws IOException {
                if (inReader.peek() == JsonToken.NULL) {
                    inReader.nextNull();
                    return null;
                }
                return expectedDate;
            }
        };

        Date actualDate = adapterWithOverride.read(in);

        assertEquals(expectedDate, actualDate);
    }

    @Test
    public void testDeserializeToDate_WithValidDateString() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.nextString()).thenReturn("Jan 1, 2020, 12:00:00 AM");
        when(in.peek()).thenReturn(JsonToken.STRING);

        Method deserializeToDateMethod = DateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        Date result = (Date) deserializeToDateMethod.invoke(dateTypeAdapter, in);

        assertNotNull(result);
    }

    @Test
    public void testDeserializeToDate_WithInvalidDateString_ThrowsJsonSyntaxException() throws Exception {
        JsonReader in = mock(JsonReader.class);
        when(in.nextString()).thenReturn("invalid-date");
        when(in.peek()).thenReturn(JsonToken.STRING);

        Method deserializeToDateMethod = DateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        assertThrows(RuntimeException.class, () -> {
            try {
                deserializeToDateMethod.invoke(dateTypeAdapter, in);
            } catch (InvocationTargetException e) {
                throw e.getCause();
            }
        });
    }
}
